<template><Head title="Lebenslauf Druckansicht"/><main class="mx-auto max-w-4xl bg-white p-10 text-gray-900"><button class="print:hidden rounded border px-4 py-2" @click="printPage">Drucken / als PDF speichern</button><header class="mt-8 border-b pb-5"><h1 class="text-3xl font-bold">{{ version.snapshot.person.vorname }} {{ version.snapshot.person.nachname }}</h1><p class="mt-1 text-lg">{{ version.snapshot.profile?.professional_headline }}</p><p class="mt-3 text-sm">{{ version.snapshot.profile?.career_goal }}</p></header><section v-for="type in Object.keys(labels)" :key="type" class="mt-7"><h2 class="border-b text-xl font-semibold">{{ labels[type] }}</h2><article v-for="entry in version.snapshot.entries.filter(item=>item.type===type)" :key="entry.id" class="mt-4"><div class="flex justify-between"><div><h3 class="font-semibold">{{ entry.title }}</h3><p class="text-sm">{{ entry.organization }} · {{ entry.location }}</p></div><p class="text-sm">{{ entry.starts_at?.slice(0,7) }} – {{ entry.current?'heute':entry.ends_at?.slice(0,7) }}</p></div><p v-if="entry.proficiency" class="text-sm">Niveau: {{ entry.proficiency }}</p><p class="mt-1 whitespace-pre-wrap text-sm text-gray-700">{{ entry.description }}</p></article></section><footer class="mt-10 border-t pt-3 text-xs text-gray-500">Lebenslauf Version {{ version.version }} · Prüfsumme {{ version.snapshot_sha256 }}</footer></main></template>
